            'Action': self.Action,
            'Effect': self.Effect,
            'Resource': self.Resource,
        }

    def merge(self, other):
        if self.Effect != other.Effect:
            raise ValueError(f"Trying to combine two statements with differing effects: {self.Effect} {other.Effect}")

